'use client';

import { motion, type Variants } from 'framer-motion';
import { ArrowRight, Bot, Check, Cpu, Gauge, ShieldCheck, Sparkles, Workflow } from 'lucide-react';
import { useState, type ComponentType, type ReactNode, useEffect, useRef } from 'react';
import IngenifyLogo from '@/components/IngenifyLogo';
import RequestAccessForm from '@/components/RequestAccessForm';
import PrismLogo from '@/components/PrismLogo';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

interface FeatureCard {
  title: string;
  description: string;
  icon: ComponentType<{ className?: string }>;
  className: string;
}


const reveal: Variants = {
  hidden: {
    opacity: 0,
    y: 28,
  },
  show: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.6,
      ease: [0.22, 1, 0.36, 1],
    },
  },
};

const trustedBy = [
  'TechCore Systems',
  'Velocity Digital',
  'Guardian Security',
  'Apex Platforms',
  'Nexus Innovation',
  'Sentinel Labs',
];

const features: FeatureCard[] = [
  {
    title: 'Architectural Excellence',
    description:
      'Full-stack mastery with modern architectures (Next.js, TypeScript, Distributed Databases). Component-driven design, real-time data synchronization, and cloud-native deployments built for scalability and modularity.',
    icon: Cpu,
    className: 'lg:col-span-2',
  },
  {
    title: 'Core Web Vitals',
    description: 'Server-side rendering and optimized LCP for lightning-fast performance at scale.',
    icon: Gauge,
    className: 'lg:col-span-1',
  },
  {
    title: 'SEO at the Foundation',
    description: 'Automated schema markup and semantic HTML structures engineered for visibility.',
    icon: Sparkles,
    className: 'lg:col-span-1',
  },
  {
    title: 'Security-by-Design',
    description: 'End-to-end encryption, JWT/OAuth2 authentication, and CSRF/XSS mitigation at every layer.',
    icon: ShieldCheck,
    className: 'lg:col-span-1',
  },
  {
    title: 'The Fortress Standard',
    description: 'Proactive vulnerability patching and rigorous compliance standards protecting business logic and user data.',
    icon: Workflow,
    className: 'lg:col-span-2',
  },
];


function SectionReveal({
  children,
  className = '',
  id,
}: {
  children: ReactNode;
  className?: string;
  id?: string;
}) {
  return (
    <motion.section
      id={id}
      initial="hidden"
      whileInView="show"
      viewport={{ once: true, amount: 0.2 }}
      variants={reveal}
      className={className}
    >
      {children}
    </motion.section>
  );
}

export default function IngenifyLanding() {
  const gridRef = useRef<HTMLDivElement>(null);
  const heroPrismRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    gsap.registerPlugin(ScrollTrigger);

    if (gridRef.current) {
      gsap.to(gridRef.current, {
        rotateX: 45,
        z: -100,
        opacity: 0.3,
        ease: 'none',
        scrollTrigger: {
          trigger: 'body',
          start: 'top top',
          end: 'bottom bottom',
          scrub: true,
        },
      });
    }

    if (heroPrismRef.current) {
      gsap.to(heroPrismRef.current, {
        rotateZ: 45,
        rotateX: 15,
        scale: 0.7,
        y: 100,
        opacity: 0.8,
        ease: 'power2.inOut',
        scrollTrigger: {
          trigger: '#hero',
          start: 'top top',
          end: 'bottom top',
          scrub: true,
        },
      });
    }
  }, []);

  return (
    <div ref={containerRef} className="infinity-theme relative min-h-screen overflow-x-clip text-[#111111] [perspective:1000px]">
      <div 
        ref={gridRef}
        className="inf-grid fixed inset-0 -z-10 [transform-origin:center_top]" 
      />

      <header className="fixed inset-x-0 top-0 z-50 border-b border-black/10 bg-white/70 backdrop-blur-xl">
        <nav className="mx-auto flex w-full max-w-6xl items-center justify-between px-6 py-4">
          <a href="#hero" className="shrink-0">
            <IngenifyLogo />
          </a>
          <div className="hidden items-center gap-8 text-sm font-medium text-[#444444] md:flex uppercase tracking-widest">
            <a href="#features" className="transition hover:text-black">
              Features
            </a>
            <a href="#lead-capture" className="transition hover:text-black">
              Request Access
            </a>
          </div>
          <a
            href="#lead-capture"
            className="inline-flex items-center gap-2 rounded-full border border-black bg-black px-5 py-2.5 text-sm font-semibold text-white transition hover:bg-zinc-800"
          >
            Get Started
            <ArrowRight className="h-4 w-4" />
          </a>
        </nav>
      </header>

      <main className="mx-auto w-full max-w-6xl px-6 pb-20 pt-32 sm:pt-48">
        <SectionReveal id="hero" className="scroll-mt-28 flex flex-col items-center text-center">
          <div className="mb-12 flex justify-center">
            <div ref={heroPrismRef} className="relative">
              <div className="absolute inset-0 bg-gradient-to-tr from-cyan-400 to-fuchsia-500 blur-3xl opacity-20 scale-150" />
              <PrismLogo size={180} />
            </div>
          </div>
          <div className="max-w-4xl">
            <p className="inf-mono inline-flex items-center gap-2 rounded-full border border-black/10 bg-black/5 px-4 py-2 text-[10px] uppercase tracking-[0.3em] text-black/60 font-bold">
              <Sparkles className="h-3 w-3" />
              Elite Engineering Partnership
            </p>
            <h1 className="inf-heading mt-8 text-5xl leading-[1.1] text-black sm:text-7xl">
              Secure, Visible, and Scalable Digital Ecosystems
            </h1>
            <p className="mx-auto mt-8 max-w-2xl text-base leading-relaxed text-[#444444] sm:text-lg">
              Ingenify bridges creative vision and technical fortitude. We engineer high-performance platforms with architectural excellence, SEO at the foundation, and security by design.
            </p>
            <div className="mt-12 flex flex-wrap justify-center gap-4">
              <a
                href="#lead-capture"
                className="inline-flex items-center gap-2 rounded-full bg-black px-8 py-4 text-sm font-bold text-white transition hover:bg-zinc-800 shadow-2xl shadow-black/10"
              >
                Request Access
                <ArrowRight className="h-4 w-4" />
              </a>
              <a
                href="#features"
                className="inf-mono inline-flex items-center gap-2 rounded-full border border-black/10 px-8 py-4 text-xs font-bold text-black transition hover:bg-black hover:text-white uppercase tracking-widest"
              >
                Technical Spec
              </a>
            </div>
          </div>

          <div className="mt-20 overflow-hidden rounded-full border border-black/5 bg-white/30 backdrop-blur-sm p-4">
            <div className="flex animate-[marquee_30s_linear_infinite] gap-6 whitespace-nowrap">
              {[...trustedBy, ...trustedBy].map((brand, index) => (
                <span
                  key={`${brand}-${index}`}
                  className="inf-mono rounded-full border border-black/5 bg-white/50 px-6 py-2 text-[10px] font-bold text-black/40 uppercase tracking-widest"
                >
                  {brand}
                </span>
              ))}
            </div>
          </div>
        </SectionReveal>

        <SectionReveal id="features" className="scroll-mt-24 py-32 border-t border-black/5">
          <div className="mb-16 max-w-2xl">
            <p className="inf-mono text-[10px] uppercase tracking-[0.4em] text-black/40 font-bold mb-4">/ Pillars</p>
            <h2 className="inf-heading text-4xl text-black sm:text-5xl">The Technical Standard</h2>
            <p className="mt-4 text-[#444444]">
              Architectural excellence, visibility by design, and fortress-standard security in every solution.
            </p>
          </div>

          <div className="grid gap-6 lg:grid-cols-3">
            {features.map((feature) => {
              const Icon = feature.icon;
              return (
                <motion.article
                  key={feature.title}
                  whileHover={{ y: -5 }}
                  transition={{ type: 'spring', stiffness: 300, damping: 20 }}
                  className={`border border-black/5 bg-white/50 backdrop-blur-md rounded-2xl p-8 hover:border-black/20 hover:shadow-xl transition-all ${feature.className}`}
                >
                  <div className="mb-6 inline-flex rounded-xl border border-black/10 bg-black/5 p-4 text-black">
                    <Icon className="h-6 w-6" />
                  </div>
                  <h3 className="inf-heading text-lg text-black mb-3">{feature.title}</h3>
                  <p className="text-sm leading-relaxed text-[#555555]">{feature.description}</p>
                </motion.article>
              );
            })}
          </div>
        </SectionReveal>

      </main>

      <SectionReveal id="lead-capture" className="scroll-mt-24 border-t border-black/5 bg-white/40 backdrop-blur-3xl py-24">
        <div className="mx-auto grid w-full max-w-6xl gap-16 px-6 lg:grid-cols-[1.1fr_1fr]">
          <div className="space-y-8">
            <p className="inf-mono inline-flex items-center gap-2 rounded-full border border-black/10 bg-black/5 px-4 py-2 text-[10px] uppercase tracking-[0.2em] text-black/60 font-bold">
              <Sparkles className="h-3.5 w-3.5" />
              The Ingenify Promise
            </p>
            <h2 className="inf-heading text-4xl text-black sm:text-5xl leading-tight">Web Solutions as Secure and Visible</h2>
            <p className="max-w-xl text-lg text-[#444444] leading-relaxed">
              Let's discuss how Ingenify can engineer high-performance, scalable digital ecosystems. We manage the complexity of the modern web so you can focus on the ingenuity of your business.
            </p>
          </div>

          <div className="border border-black/10 bg-white/50 backdrop-blur-sm rounded-2xl p-8 sm:p-10 shadow-2xl shadow-black/5">
            <RequestAccessForm />
          </div>
        </div>
      </SectionReveal>

      <footer className="border-t border-black/5 py-12">
        <div className="mx-auto flex w-full max-w-6xl flex-wrap items-center justify-between gap-6 px-6 text-xs text-[#666666] font-bold uppercase tracking-widest">
          <IngenifyLogo compact className="opacity-80 invert filter" />
          <p>© {new Date().getFullYear()} Ingenify / Technical Standards</p>
        </div>
      </footer>
    </div>
  );
}
